  ('pukao-e7b0146b-moex-00046', 'pukao-e7b0146b', 'pukao-e7b0146b-moex-110-9a70b52a', 'sub-pukao-e7b0146b-01', NULL, 'essay', '試論「文化科技」政策內涵、效用及尚有那些障礙需要突破？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:55+00:00", "source_pdf_sha1": "7babfe25c854", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "408", "s": "0206", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "文化行政概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "文化行政"}'::jsonb, NULL),
  ('pukao-e7b0146b-moex-00047', 'pukao-e7b0146b', 'pukao-e7b0146b-moex-110-9a70b52a', 'sub-pukao-e7b0146b-01', NULL, 'essay', '全球新冠疫情嚴峻之際，所有展演場所關閉，各種展演活動停止。試論
