  ('pukao-e7b0146b-moex-00048', 'pukao-e7b0146b', 'pukao-e7b0146b-moex-110-9a70b52a', 'sub-pukao-e7b0146b-01', NULL, 'essay', '近年舉辦「全國文化會議」、「全國文化資產會議」、「全國博物館論壇」、
「全國社區營造會議」等鼓勵公眾參與的文化政策形成機制與過程。這些
關乎各面向文化政策的全國會議都有「由下而上」、「廣徵民意」的精神。
試論舉辦這些全國會議的方式為何？（5分）這般看似「由下而上」、「廣
徵民意」的舉辦模式可能有什麼問題？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:55+00:00", "source_pdf_sha1": "7babfe25c854", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "408", "s": "0206", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "文化行政概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "文化行政"}'::jsonb, NULL)
